import{_ as a,o as r,c as i,ag as t}from"./chunks/framework.B45ElpZ1.js";const p=JSON.parse('{"title":"tradecli wiki","description":"Documentation for the tradecli AI trading assistant for Indian markets.","frontmatter":{"title":"tradecli wiki","description":"Documentation for the tradecli AI trading assistant for Indian markets.","head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/"}]]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function l(n,e,s,d,h,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="tradecli-wiki" tabindex="-1">tradecli wiki <a class="header-anchor" href="#tradecli-wiki" aria-label="Permalink to &quot;tradecli wiki&quot;">​</a></h1><p>Documentation for <code>tradecli</code> — a terminal-based AI trading assistant for Indian markets.</p><h2 id="what-is-tradecli" tabindex="-1">What is tradecli? <a class="header-anchor" href="#what-is-tradecli" aria-label="Permalink to &quot;What is tradecli?&quot;">​</a></h2><p><code>tradecli</code> is a command-line AI agent that drives your browser and MCP-native market tools to research stocks, learn trading, manage portfolios, and analyze live trade setups across NSE and BSE. It connects to Groww and Zerodha through MCP, uses Screener.in and TradingView, and adapts to where you are in your trading journey through five personas: Learner, Investor, Trader, Pro Trader, and Portfolio Manager.</p><p>Everything the agent does you can see and audit in your terminal — no hidden actions, no cloud service, your broker credentials stay on your machine.</p><h2 id="new-here" tabindex="-1">New here? <a class="header-anchor" href="#new-here" aria-label="Permalink to &quot;New here?&quot;">​</a></h2><p>Start with → <a href="/wiki/getting-started/quick-start">Quick Start</a></p><h2 id="explore-the-docs" tabindex="-1">Explore the docs <a class="header-anchor" href="#explore-the-docs" aria-label="Permalink to &quot;Explore the docs&quot;">​</a></h2><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h3><h4 id="quick-start" tabindex="-1"><a href="/wiki/getting-started/quick-start">Quick Start</a> <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;[Quick Start](/getting-started/quick-start)&quot;">​</a></h4><ul><li>Install via Homebrew</li><li>Configure an LLM provider</li><li>Run <code>tradecli doctor</code></li><li>Pick your first persona</li><li>Launch the TUI</li></ul><h4 id="broker-setup" tabindex="-1"><a href="/wiki/getting-started/broker-setup">Broker Setup</a> <a class="header-anchor" href="#broker-setup" aria-label="Permalink to &quot;[Broker Setup](/getting-started/broker-setup)&quot;">​</a></h4><ul><li>Supported brokers</li><li>Groww connection</li><li>Zerodha Kite connection</li><li>Token refresh and reauth</li><li>Troubleshooting</li></ul><h4 id="browser-setup" tabindex="-1"><a href="/wiki/getting-started/browser-setup">Browser Setup</a> <a class="header-anchor" href="#browser-setup" aria-label="Permalink to &quot;[Browser Setup](/getting-started/browser-setup)&quot;">​</a></h4><ul><li>Why a dedicated browser</li><li>Chrome/Chromium requirements</li><li>The tradecli browser profile</li><li>First-run flow</li><li>Troubleshooting</li></ul><h3 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h3><h4 id="personas-modes" tabindex="-1"><a href="/wiki/guides/personas">Personas &amp; Modes</a> <a class="header-anchor" href="#personas-modes" aria-label="Permalink to &quot;[Personas &amp; Modes](/guides/personas)&quot;">​</a></h4><ul><li>Picking one</li><li>Switching</li></ul><h4 id="learner-mode" tabindex="-1"><a href="/wiki/guides/learner">Learner Mode</a> <a class="header-anchor" href="#learner-mode" aria-label="Permalink to &quot;[Learner Mode](/guides/learner)&quot;">​</a></h4><ul><li>How it works</li><li>Typical prompts</li><li>Switching away and back</li></ul><h4 id="investor" tabindex="-1"><a href="/wiki/guides/investor">Investor</a> <a class="header-anchor" href="#investor" aria-label="Permalink to &quot;[Investor](/guides/investor)&quot;">​</a></h4><ul><li>What it&#39;s for</li><li>Primary tools</li><li>Typical prompts</li></ul><h4 id="trader" tabindex="-1"><a href="/wiki/guides/trader">Trader</a> <a class="header-anchor" href="#trader" aria-label="Permalink to &quot;[Trader](/guides/trader)&quot;">​</a></h4><ul><li>What it&#39;s for</li><li>Primary tools</li><li>Typical prompts</li></ul><h4 id="pro-trader" tabindex="-1"><a href="/wiki/guides/pro-trader">Pro Trader</a> <a class="header-anchor" href="#pro-trader" aria-label="Permalink to &quot;[Pro Trader](/guides/pro-trader)&quot;">​</a></h4><ul><li>Chart-first trade decisions</li><li>MCP-native TradingView workflows</li><li>Trade path routing</li><li>Pine scripts and backtests</li><li>Typical prompts</li></ul><h4 id="portfolio-manager" tabindex="-1"><a href="/wiki/guides/portfolio-manager">Portfolio Manager</a> <a class="header-anchor" href="#portfolio-manager" aria-label="Permalink to &quot;[Portfolio Manager](/guides/portfolio-manager)&quot;">​</a></h4><ul><li>What it&#39;s for</li><li>Primary tools</li><li>Setup</li><li>Typical prompts</li></ul><h4 id="channels-api" tabindex="-1"><a href="/wiki/guides/channels-api">Channels &amp; API</a> <a class="header-anchor" href="#channels-api" aria-label="Permalink to &quot;[Channels &amp; API](/guides/channels-api)&quot;">​</a></h4><ul><li>What is a channel</li><li>The TUI channel</li><li>Telegram</li><li>WhatsApp</li><li>Gateway HTTP API</li></ul>',30)])])}const g=a(o,[["render",l]]);export{p as __pageData,g as default};
